import{_ as r,o,c as n,a0 as d}from"./chunks/framework.DV6pVIgV.js";const b=JSON.parse('{"title":"遷移上雲","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/16.md","filePath":"clf-c02/16.md","lastUpdated":1783610848000}'),a={name:"clf-c02/16.md"};function s(e,t,g,i,l,h){return o(),n("div",null,[...t[0]||(t[0]=[d(`<h1 id="遷移上雲" tabindex="-1">遷移上雲 <a class="header-anchor" href="#遷移上雲" aria-label="Permalink to &quot;遷移上雲&quot;">​</a></h1><p>雲端採用框架、七大遷移策略、資料庫與資料搬移工具。這章講「怎麼把既有的系統與資料從地端搬到 AWS」——重點是<strong>規劃框架（CAF）</strong>、<strong>七種搬法（7R）</strong>，以及線上 / 離線搬資料的工具怎麼選。</p><h2 id="為什麼遷移需要框架與策略" tabindex="-1">為什麼遷移需要框架與策略 <a class="header-anchor" href="#為什麼遷移需要框架與策略" aria-label="Permalink to &quot;為什麼遷移需要框架與策略&quot;">​</a></h2><p>把一整間公司的系統搬上雲，牽涉到組織、技能、安全、成本、相依關係——不是「複製貼上」這麼簡單。所以 AWS 提供兩個工具幫你想清楚：<strong>CAF（規劃的框架）</strong> 與 <strong>7R（每個應用怎麼搬的策略）</strong>。</p><h2 id="aws-雲端採用框架-cloud-adoption-framework-caf" tabindex="-1">AWS 雲端採用框架（Cloud Adoption Framework, CAF） <a class="header-anchor" href="#aws-雲端採用框架-cloud-adoption-framework-caf" aria-label="Permalink to &quot;AWS 雲端採用框架（Cloud Adoption Framework, CAF）&quot;">​</a></h2><p>CAF 幫組織<strong>有系統地規劃與執行上雲</strong>，從六個面向檢視準備度。六個面向分成兩組：</p><p><strong>商業能力（Business Capabilities）— 先想清楚「為什麼、誰來做」：</strong></p><table tabindex="0"><thead><tr><th>面向</th><th>關注什麼</th></tr></thead><tbody><tr><td><strong>Business（商業）</strong></td><td>確保雲端投資<strong>對齊商業目標</strong></td></tr><tr><td><strong>People（人員）</strong></td><td>角色、技能、組織結構、教育訓練、變革管理</td></tr><tr><td><strong>Governance（治理）</strong></td><td>管理與衡量雲端投資、專案 / 投資組合管理</td></tr></tbody></table><p><strong>技術能力（Technical Capabilities）— 再處理「怎麼建、怎麼守、怎麼跑」：</strong></p><table tabindex="0"><thead><tr><th>面向</th><th>關注什麼</th></tr></thead><tbody><tr><td><strong>Platform（平台）</strong></td><td>建立 / 現代化雲端平台與架構</td></tr><tr><td><strong>Security（安全）</strong></td><td>達成安全與合規目標</td></tr><tr><td><strong>Operations（營運）</strong></td><td>運行、監控、維運雲端工作負載</td></tr></tbody></table><blockquote><p>前三個（商業 / 人員 / 治理）偏「人與管理」，後三個（平台 / 安全 / 營運）偏「技術與執行」。</p></blockquote><h2 id="七大遷移策略-the-7-rs" tabindex="-1">七大遷移策略（The 7 Rs） <a class="header-anchor" href="#七大遷移策略-the-7-rs" aria-label="Permalink to &quot;七大遷移策略（The 7 Rs）&quot;">​</a></h2><p>每一個既有應用程式，可以選七種搬法之一：</p><table tabindex="0"><thead><tr><th>策略</th><th>做什麼</th><th>例子</th></tr></thead><tbody><tr><td><strong>Rehost</strong></td><td>原封不動搬上雲，不改架構（最快）</td><td>把地端 VM 直接複製成 EC2</td></tr><tr><td><strong>Replatform</strong></td><td>搬上雲時做小幅優化，不動核心架構</td><td>把自管 MySQL 換成託管 <strong>RDS</strong></td></tr><tr><td><strong>Refactor / Re-architect</strong></td><td>重新設計成雲端原生（最費工、效益最大）</td><td>把單體應用改成微服務 + 無伺服器</td></tr><tr><td><strong>Repurchase</strong></td><td>換成另一個產品，常是 SaaS</td><td>自架 CRM → 改用 Salesforce</td></tr><tr><td><strong>Retain</strong></td><td>暫時保留在地端（還沒準備好 / 沒必要搬）</td><td>即將汰除、或有相依限制的系統</td></tr><tr><td><strong>Retire</strong></td><td>直接淘汰、移除不再需要的東西</td><td>關掉沒人用的舊系統，省成本</td></tr><tr><td><strong>Relocate</strong></td><td>把基礎設施整批搬到雲、不買新硬體、不改程式</td><td>VMware Cloud on AWS</td></tr></tbody></table><blockquote><ul><li>「原封不動、最快搬上雲」→ <strong>Rehost</strong></li><li>「搬上雲順便換成託管服務（如 RDS）但不大改」→ <strong>Replatform</strong></li><li>「重新設計成雲端原生、投入最多」→ <strong>Refactor</strong></li><li>「換成 SaaS / 別的產品」→ <strong>Repurchase</strong></li><li>「這個系統先不搬」→ <strong>Retain</strong></li><li>「這個系統不要了」→ <strong>Retire</strong></li></ul></blockquote><h2 id="遷移服務與工具" tabindex="-1">遷移服務與工具 <a class="header-anchor" href="#遷移服務與工具" aria-label="Permalink to &quot;遷移服務與工具&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服務</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>AWS Migration Hub</strong></td><td><strong>集中追蹤</strong>遷移進度的儀表板（跨各種遷移工具一覽）</td></tr><tr><td><strong>AWS Application Migration Service（MGN）</strong></td><td>自動化 <strong>lift-and-shift（Rehost）</strong>，把地端伺服器複製到 AWS</td></tr><tr><td><strong>AWS Application Discovery Service</strong></td><td><strong>盤點</strong>地端伺服器與相依關係，協助規劃遷移</td></tr></tbody></table><h2 id="資料庫遷移" tabindex="-1">資料庫遷移 <a class="header-anchor" href="#資料庫遷移" aria-label="Permalink to &quot;資料庫遷移&quot;">​</a></h2><table tabindex="0"><thead><tr><th>服務</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>AWS DMS（Database Migration Service）</strong></td><td>把資料庫搬到 AWS，<strong>搬遷期間來源資料庫仍可運作</strong>（降低停機）</td></tr><tr><td><strong>AWS SCT（Schema Conversion Tool）</strong></td><td>來源與目標是<strong>不同引擎</strong>時，先<strong>轉換 schema</strong></td></tr></tbody></table><ul><li><strong>同質遷移（Homogeneous）</strong>：來源與目標<strong>同引擎</strong>（MySQL → MySQL）→ 直接用 <strong>DMS</strong></li><li><strong>異質遷移（Heterogeneous）</strong>：來源與目標<strong>不同引擎</strong>（Oracle → Aurora）→ 先用 <strong>SCT 轉換 schema</strong>，再用 <strong>DMS</strong> 搬資料</li></ul><h2 id="搬移資料-線上-vs-離線" tabindex="-1">搬移資料：線上 vs 離線 <a class="header-anchor" href="#搬移資料-線上-vs-離線" aria-label="Permalink to &quot;搬移資料：線上 vs 離線&quot;">​</a></h2><p>先問關鍵問題：<strong>網路頻寬夠不夠？</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>資料量 vs 頻寬</span></span>
<span class="line"><span>  頻寬充足、可接受傳輸時間  → 線上（走網路）</span></span>
<span class="line"><span>  頻寬不足 / 資料量巨大 / 偏遠無網路 → 離線（實體裝置寄送）</span></span></code></pre></div><p>如果用現有網路傳要超過一週，就該考慮離線。例如 100TB 走 1Gbps 線路約要 12 天——這種就改用 Snow 裝置寄送更快。</p><h3 id="線上傳輸" tabindex="-1">線上傳輸 <a class="header-anchor" href="#線上傳輸" aria-label="Permalink to &quot;線上傳輸&quot;">​</a></h3><table tabindex="0"><thead><tr><th>服務</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>AWS DataSync</strong></td><td>自動化透過<strong>網路</strong>搬移大量資料（地端 ↔ AWS、或 AWS 儲存服務之間）</td></tr><tr><td><strong>AWS Transfer Family</strong></td><td>用 <strong>SFTP / FTPS / FTP</strong> 把檔案傳進 / 傳出 S3、EFS</td></tr><tr><td><strong>AWS Storage Gateway</strong></td><td>混合雲：地端 ↔ 雲端儲存的橋</td></tr></tbody></table><h3 id="離線傳輸-aws-snow-家族" tabindex="-1">離線傳輸：AWS Snow 家族 <a class="header-anchor" href="#離線傳輸-aws-snow-家族" aria-label="Permalink to &quot;離線傳輸：AWS Snow 家族&quot;">​</a></h3><table tabindex="0"><thead><tr><th>裝置</th><th>容量級距</th><th>招牌特徵</th></tr></thead><tbody><tr><td><strong>Snowcone</strong></td><td>最小（8TB HDD / 14TB SSD）</td><td>最輕最可攜，<strong>空間受限 / 嚴苛環境</strong></td></tr><tr><td><strong>Snowball Edge</strong></td><td>TB ~ PB</td><td>主力；分 Storage Optimized / Compute Optimized；<strong>可在裝置上跑 EC2 / Lambda 做邊緣運算</strong></td></tr><tr><td><strong>Snowmobile</strong></td><td>Exabyte 級（最高 100PB）</td><td>一台<strong>貨櫃車</strong>，搬整個資料中心</td></tr></tbody></table><ul><li>「<strong>小、可攜、嚴苛環境</strong>」→ <strong>Snowcone</strong></li><li>「<strong>幾十 TB ~ PB、頻寬不足</strong>」→ <strong>Snowball Edge</strong></li><li>「<strong>EB 級 / 搬整座資料中心</strong>」→ <strong>Snowmobile</strong></li></ul><blockquote><p><strong>重要時效提醒</strong>：Snow 家族已大幅縮編。Snowmobile（貨櫃車）已於 2024 年退役。Snowcone 已於 2024/11 停售。現行只剩 Snowball Edge（Storage Optimized 210TB / Compute Optimized 104 vCPU）。</p></blockquote><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>有系統地規劃整體上雲（六面向）</td><td><strong>Cloud Adoption Framework（CAF）</strong></td></tr><tr><td>原封不動、最快搬上雲</td><td><strong>Rehost</strong>（lift and shift）</td></tr><tr><td>搬上雲順便換成 RDS 等託管、不大改</td><td><strong>Replatform</strong></td></tr><tr><td>重新設計成雲端原生</td><td><strong>Refactor / Re-architect</strong></td></tr><tr><td>換成 SaaS / 別的產品</td><td><strong>Repurchase</strong></td></tr><tr><td>這系統先不搬 / 不要了</td><td><strong>Retain</strong> / <strong>Retire</strong></td></tr><tr><td>集中追蹤遷移進度</td><td><strong>Migration Hub</strong></td></tr><tr><td>自動化把伺服器複製上雲（Rehost）</td><td><strong>Application Migration Service（MGN）</strong></td></tr><tr><td>搬資料庫、來源不能停太久</td><td><strong>DMS</strong></td></tr><tr><td>來源與目標資料庫引擎不同</td><td><strong>SCT</strong>（轉 schema）+ DMS</td></tr><tr><td>透過網路搬大量資料</td><td><strong>DataSync</strong></td></tr><tr><td>用 SFTP 傳檔案進 S3</td><td><strong>Transfer Family</strong></td></tr><tr><td>頻寬不足 / 資料量巨大，離線搬</td><td><strong>Snow 家族（Snowball Edge）</strong></td></tr></tbody></table>`,32)])])}const p=r(a,[["render",s]]);export{b as __pageData,p as default};
